97		// Validate version
98		if c.Version == "" {
99			errors = append(errors, &ConfigError{
100				Field:      "version",
101				Message:    "version is required",
102				Suggestion: "add 'version: \"1.0\"' to your config",
103			})
104		}
105	
106		// Validate library configuration
107		if c.Library != nil && c.Library.Repository != nil {
108			if c.Library.Repository.URL == "" {
